      "copy_goal_to_clipboard": "📋 Detuo ebumnuche na clipboard",
      "all_lesson_plans": "← Atụmatụ nkuzi niile",
      "learning_objectives": "🎯 Ebumnobi mmụta",
      "lesson_plan_templates": "📚 Ihe nlereanya atụmatụ nkuzi",
      "ready_to_use_micro_units_3_5_days_each": "Obere nkeji njikere-iji (ụbọchị 3-5 nke ọ bụla) maka isiokwu nkebi nkịtị. Atụmatụ ọ bụla na-ejikọ ọrụ na ihu Fraction Lab akọwapụtara ka i nwee ike igosi ma ọ bụ kenye ozugbo.",
      "where_do_fractions_come_from": "Ebee ka nkebi si abịa?",
      "the_earliest_fraction_notation_dates_t": "Odide nkebi mbụ dị site n'oge Ijipt oge ochie gburugburu 1800 TOA. Ndị Ijipt jiri \"nkebi otu\" — naanị nkebi nwere nọmba elu 1 (dịka 1/2, 1/3, 1/4). Ha dere nkebi ọ bụla ọzọ dị ka mkpokọta nke nkebi otu: 2/5 = 1/3 + 1/15. Odide mkpịsị ọgbara ọhụrụ (nọmba elu n'elu nọmba ala) sitere n'aka ndị mgbakọ Arabik nke etiti afọ gburugburu 1200 OA.",
      "where_do_the_fraction_words_come_from": "Ebee ka okwu nkebi si abịa?",
      "numerator_comes_from_the_latin_numerar": "\"Numerator\" sitere na Latin \"numerare\" (ịgụ) — ọ na-agụ akụkụ ole. \"Denominator\" sitere na \"denominare\" (ịkpọ aha) — ọ na-akpọ aha nha nke akụkụ. Ọnụ: nọmba ala na-akpọ aha ụdị mpempe; nọmba elu na-agụ ole n'ime mpempe ndị ahụ i nwere.",
      "the_decimal_point": "Isi decimal",
      "decimals_as_we_know_them_were_populari": "Decimal dị ka anyị maara ha ka Simon Stevin mere ka ọ bụrụ nke a ma ama na 1585 n'akwụkwọ ya \"De Thiende\" (Nke Iri). Tupu nke ahụ, nkebi bụ naanị ụzọ e si egosi ọnụọgụgụ na-abụghị nke zuru ezu. Isi decimal ka anabatara zuru ụwa ọnụ naanị na 1700s.",
      "what_does_percent_mean": "Gịnị ka pasent pụtara?",
      "percent_comes_from_the_latin_per_centu": "\"Percent\" sitere na Latin \"per centum\" — \"kwa narị.\" Ya mere 25% pụtara kpọmkwem 25 kwa 100, ma ọ bụ 25/100. Akara % malitere site na mbiri okwu \"per c.\" na edemede azụmahịa Italian nke narị afọ nke 15.",
      "what_is_a_reciprocal": "Gịnị bụ reciprocal?",
      "the_reciprocal_of_a_b_is_b_a_flip_it_u": "Reciprocal nke a/b bụ b/a — tụgharịa ya isi ala. Nkebi ọ bụla na-abụghị efu nwere reciprocal. Ngwaahịa nke nkebi na reciprocal ya na-abụkarị 1: (3/4) × (4/3) = 12/12 = 1. Nke a bụ ihe mere ịkewa site na nkebi bụ otu ihe na ịmụba site na reciprocal ya.",
      "why_is_1_2_the_most_used_fraction": "Gịnị mere 1/2 ji bụrụ nkebi a na-ejikarị eme ihe?",
      "1_2_is_the_most_common_fraction_in_eve": "1/2 bụ nkebi kacha na okwu kwa ụbọchị n'ihi na ọ nọ kpọmkwem n'etiti 0 na 1. Ọ bụkwa naanị nkebi anyị na-ekwukarị n'okwu: \"ọkara\" karịa \"otu n'elu abụọ.\" Asụsụ ndị ọzọ nwekwara okwu pụrụ iche maka 1/3 na 1/4 (nke atọ, otu ụzọ n'ụzọ anọ).",
      "pizza_is_mathematical": "Pizza bụ nke mgbakọ",
      "a_pizza_is_a_perfect_fraction_model_be": "Pizza bụ ihe nlereanya nkebi zuru oke n'ihi na ọ bụ okirikiri (ya mere mpempe niile na-esite n'etiti), mpempe dị mfe ịgụ, na ihe nlereanya na-adaba na nkọwa mgbakọ nkịtị: nkebi n/d bụ n akụkụ hara nhata n'ime d mkpokọta akụkụ hara nhata.",
      "when_fractions_are_not_enough": "Mgbe nkebi ezughị",
      "some_numbers_like_and_2_cannot_be_writ": "Ụfọdụ nọmba, dịka π na √2, enweghị ike ide dịka nkebi nke ọnụọgụgụ abụọ zuru ezu. A na-akpọ ndị a nọmba na-enweghị isi. Ndị Pythagorean (gburugburu 500 TOA) e kwuru na ha gburu onye mgbakọ Hippasus mgbe o gosipụtara na enweghị ike ide √2 dịka nkebi.",
      "continued_fractions": "Nkebi na-aga n'ihu",
      "any_real_number_can_be_written_as_a_co": "Ọ bụla nọmba n'ezie nwere ike ide dịka \"nkebi na-aga n'ihu\" — nkebi dị n'ime dịka 1 + 1/(2 + 1/(2 + 1/(2 + ...))). Nke a na-enye nkọwa nkebi kachasị mma. π ≈ 22/7 site n'okwu mbụ ole na ole; nke ka mma bụ 355/113.",
      "fractions_in_music": "Nkebi na egwu",
      "musical_pitch_ratios_are_fractions_the": "Ọ̀tụ̀tụ̀ ụda egwu bụ nkebi. Octave bụ ọ̀tụ̀tụ̀ 2:1 (ugboro ugboro na-abaji ụba). Nke ise zuru oke bụ 3:2. Nke atọ buru ibu bụ 5:4. Pythagoras chọpụtara na ọ̀tụ̀tụ̀ ọnụọgụgụ dị mfe na-emepụta ụda dị nkọ.",
      "why_the_common_denominator": "Gịnị mere nọmba ala nkịtị?",
      "two_pizzas_can_only_be_combined_if_the": "Enwere ike ijikọta pizza abụọ naanị ma ọ bụrụ na e bekwara ha ka ọ bụrụ mpempe otu nha. Nọmba ala dị iche = mpempe nha dị iche = enweghị ike ijikọta ozugbo. Nọmba ala nkịtị pụtara kpọmkwem \"mpempe otu nha.\"",
      "baseball_stats_are_fractions": "Ọnụọgụgụ baseball bụ nkebi",
      "a_batting_average_like_333_means_1_3_o": "Nkezi ịkụ dịka .333 pụtara 1/3 nke ịkụ na-eweta ịtụ. ERA nke onye na-atụ, pasent-nọ-n'ọnụ, pasent slugging — ha niile bụ nkebi. Baseball bụ egwuregwu mbụ mere ka ụdị echiche ọnụọgụgụ a bụrụ nke a ma ama, malite na 1850s.",
      "cuisenaire_rods": "Mkpanaka Cuisenaire",
      "georges_cuisenaire_was_a_belgian_prima": "Georges Cuisenaire bụ onye nkuzi elementrị Beljọm na 1950s bụ onye chepụtara mkpanaka nwere agba nke ogologo 1 ruo 10 iji nyere ụmụaka aka ijide mmekọrịta ọnụọgụgụ gụnyere nkebi. \"Mgbidi nkebi\" ị na-ahụ n'ọtụtụ klas bụ nwa dijitalụ nke mkpanaka anụ ahụ ya.",
      "fractions_in_ancient_china": "Nkebi na China oge ochie",
      "the_chinese_mathematical_text_nine_cha": "Ederede mgbakọ China \"Isi Iri na Otu na Nka Mgbakọ\" (gburugburu 100 TOA) gụnyere mgbakọ nkebi, gụnyere usoro maka ịchọta nọmba ala nkịtị nke hara nhata na mgbakọ na ihe anyị na-akụzi taa.",
      "computers_and_fractions": "Kọmputa na nkebi",
      "computers_store_decimal_fractions_in_b": "Kọmputa na-echekwa nkebi decimal na binary. Decimal 0.1 enweghị ike igosipụta kpọmkwem na binary — ọ na-aghọ nkebi na-emegharị na ntọala 2. Nke a bụ ihe mere 0.1 + 0.2 ji na-enye 0.30000000000000004 mgbe ụfọdụ n'asụsụ mmemme.",
      "fraction_adjacent_sayings": "🗣 Okwu ndị metụtara nkebi",
      "dogs_spend_about_1_2_their_lives_sleep": "Nkịta na-eji ihe dị ka 1/2 nke ndụ ha arahụ ụra. Nkịta gbara afọ 12 arahụla ụra ihe dị ka afọ 6.",
      "cats_sleep_about_2_3_of_every_day_that": "Nwamba na-arahụ ụra ihe dị ka 2/3 nke ụbọchị ọ bụla. Nke ahụ bụ awa 16 kwa ụbọchị.",
      "elephants_drink_about_1_8_of_their_bod": "Enyí na-aṅụ ihe dị ka 1/8 nke ịdị arọ ahụ ha na mmiri kwa ụbọchị. Enyí dị paụndị 12,000 na-aṅụ paụndị 1,500 mmiri!",
      "a_blue_whale_s_tongue_weighs_about_1_2": "Ire nke whale acha anụnụ anụnụ dị arọ ihe dị ka 1/2 nke obere ụgbọ ala (~paụndị 6,000).",
      "a_bee_visits_about_1_500_flowers_to_ma": "Aṅụ na-eleta ihe dị ka okooko osisi 1,500 iji mepụta 1/12 spoon mmanụ aṅụ.",
      "a_giraffe_s_neck_is_about_1_3_of_its_t": "Olu giraffe dị ihe dị ka 1/3 nke ogologo ya niile.",
      "a_snail_moves_at_about_1_40_of_a_mile_": "Ejùnà na-aga na ihe dị ka 1/40 nke maịl kwa awa. Ọ ga-ewe awa 40 iji gaa maịl 1.",
      "a_kangaroo_can_leap_a_distance_about_3": "Kangaroo nwere ike ịwụ anya ihe dị ka 3/2 nke ogologo ahụ ya n'otu mmawụ.",
      "a_dolphin_sleeps_with_half_its_brain_a": "Dolphin na-arahụ ụra na ọkara ụbụrụ ya n'otu oge — naanị 1/2 nke ụbụrụ na-ezu ike ebe ọkara nke ọzọ nọ na-eche nche.",
      "a_giant_tortoise_can_live_to_150_years": "Mbekwu buru ibu nwere ike ibi ruo afọ 150+. Mbekwu gbara afọ 100 ebiela 2/3 nke ndụ ya nwere ike.",
      "animal_fractions": "🐾 Nkebi anụmanụ",
      "real_world_fraction_facts_from_the_ani": "Eziokwu nkebi nke ụwa n'ezie site n'alaeze anụmanụ. Jiri ya dịka ntinye akwụkwọ akụkọ, ihe na-adọta uche, ma ọ bụ njikọ n'ofe usoro na sayensị.",
