      "thermals": "Usoro Okpomọkụ",
      "thermals_are_columns_of_rising_warm_ai": "Usoro okpomọkụ bụ ogidi ikuku na-ekpo ọkụ na-arịgo nke a na-emepụta mgbe anyanwụ na-ekpo ala ọkụ n'ụzọ na-ezighị ezi. Elu gbara ọchịchịrị (ebe ịdọba ụgbọala, ubi a kọrọ akọ) na-emepụta usoro siri ike karịa elu ndị dị nfe (mmiri, ọhịa). Nnụnụ na-efe efe dị ka egbe na udele na-arịgo na okirikiri na usoro okpomọkụ, na-enweta ịdị elu na-akụghị nku. Mgbe ahụ ha na-amịpụ gaa n'usoro na-esote, na-emepụta “ okporo ụzọ okpomọkụ ”, ụzọ ngwa ngwa nke na-arụ ọrụ nke ọma na mbara igwe.",
      "orographic_lift": "Mbuli Ugwu",
      "when_wind_encounters_a_mountain_it_is_": "Mgbe ikuku zutere ugwu, a na-akwanye ya n'elu n'akụkụ mgbada nke na-eche ikuku ihu. Nke a na-emepụta usoro ikuku na-arịgo nke nnụnụ na-efe efe (dị ka egbe ọla edo) na-eji n'elu ugwu. N'akụkụ nke anaghị eche ikuku ihu, ikuku na-emikpu ngwa ngwa, na-emepụta mpaghara “rotor” dị ize ndụ nke ikuku na-akpali na-agbada. Ọ bụ ya mere nnụnụ na ndị ọkwọ ụgbọ elu ji ezere akụkụ ugwu nke anaghị eche ikuku ihu.",
      "sea_breezes": "Ikuku Oke Osimiri",
      "land_heats_faster_than_water_during_th": "Ala na-ekpo ọkụ ngwa ngwa karịa mmiri n'ehihie. Ikuku na-ekpo ọkụ na-arịgo n'elu ala ma ikuku jụrụ oyi na-esi n'oke osimiri bịa were ọnọdụ ya, na-emepụta “ikuku oke osimiri” gaa n'ụsọ oké osimiri. N'abalị usoro na-atụgharị. Nnụnụ na-akwaga na-eji ikuku ụsọ osimiri ndị a a pụrụ ịkọ chekwaa ike. Mpaghara njikọ, ebe ikuku oke osimiri na-ezute ikuku ime obodo, na-emepụtakarị usoro okpomọkụ nke nnụnụ na-eji enweta ịdị elu.",
      "jet_streams": "Mmiri Jet",
      "high_altitude_jet_streams_are_narrow_b": "Mmiri jet ịdị elu dị elu bụ usoro dị warịị nke ikuku dị oke ọsọ (100-200 mph) na ụkwụ 30,000-40,000. Ọ bụ ezie na ọtụtụ nnụnụ na-efe n'okpuru mmiri jet nke ukwuu, ụfọdụ ndị na-akwaga dị ka Bar-tailed Godwit na-arịgo n'elu ụkwụ 20,000 iji jide ikuku ịdị elu dị elu dị mma. Achọpụtara ọgazị site na radar na ụkwụ 29,000 n'elu Himalaya, ebe oxygen dị ntakịrị na okpomọkụ na-adaba ruo -50 °F.",
      "wind_shear": "Mbipụ Ikuku",
      "wind_shear_is_a_sudden_change_in_wind_": "Mbipụ ikuku bụ mgbanwe mberede na ọsọ ma ọ bụ ntụzịaka ikuku n'anya dị mkpụmkpụ. Ọ dị ize ndụ maka nnụnụ na ụgbọ elu. N'oge oké mmiri, obere mgbawa (ogidi mberede nke ikuku na-agbada) na-emepụta mbipụ ikuku siri ike nso n'ala. Nnụnụ na-achọpụta mgbanwe nrụgide ma na-anọkarị ọdụ mbugharị mgbe ihu oké mmiri na-abịaru nso.",
      "beaufort_scale": "Ọ̀tụ̀tụ̀ Beaufort",
      "admiral_sir_francis_beaufort_created_h": "Admiral Sir Francis Beaufort mepụtara ọ̀tụ̀tụ̀ ikuku ya n'afọ 1805 dabere na mmetụta ikuku na ụgbọ mmiri nwere ọkọ. Ọ̀tụ̀tụ̀ Beaufort nke oge a na-eji nleba anya ala: ike 0 (dị jụụ) = anwụrụ ọkụ na-arịgo kwụ ọtọ; ike 6 (ikuku siri ike) = alaka buru ibu na-efegharị, nche anwụ na-atụgharị; ike 12 (oké ifufe) = mbibi. Ọtụtụ nnụnụ na-ahọrọ ịkwaga n'ike 2-4 (ikuku dị nro ruo etiti).",
      "how_birds_use_wind": "🐦 Otú Nnụnụ si Eji Ikuku",
      "tail_winds": "Ikuku Azụ: ",
      "migrants_strongly_prefer_flying_with_t": "Ndị na-akwaga na-ahọrọ nke ukwuu ife na ikuku n'azụ ha. Ọbụna ikuku azụ nke 15 mph na-abawanye ọsọ nnụnụ n'ala okpukpu abụọ nke ọma na otu mmefu ike. Ọmụmụ ihe na-egosi mmegharị nnụnụ dị okpukpu 10 karịa n'ụbọchị mbugharị nwere ikuku azụ dị mma karịa n'ụbọchị ikuku ihu.",
      "dynamic_soaring": "Ife Ike: ",
      "albatrosses_exploit_wind_speed_gradien": "Albatross na-eji mgbada ọsọ ikuku n'elu ebili mmiri oke osimiri. Site n'ịgbanwe n'etiti ịrịgo n'ime ikuku ọsọ ọsọ na imikpu n'ime ikuku dị nwayọọ nso n'elu, ha na-ewepụta ike site na mbipụ ikuku n'onwe ya. Albatross nwere ike ife maịl kachasị na-akụghị nku nke ukwuu.",
      "slope_soaring": "Ife Mgbada: ",
      "when_wind_hits_a_cliff_face_or_ridge_t": "Mgbe ikuku kụrụ ihu nkume ma ọ bụ mgbada, ikuku na-alọghachi na-emepụta “ebili mmiri” nke mbuli n'akụkụ ahịrị mgbada. Nnụnụ na-achụ nta na-efe n'elu usoro mgbada ndị a n'oge mbugharị, na-ejikọ usoro ugwu dị ka ịwụ na nkume. Hawk Mountain na Pennsylvania bụ ihe a ma ama maka ihe omume a.",
      "experiment_place_a_thermal_and_a_mount": "Nnwale: Tinye usoro okpomọkụ na ugwu n'ọhịa, wee tinye nnụnụ. Lelee ya ka ọ na-efe n'elu usoro na-arịgo!",
      "birds_as_weather_forecasters": "🌦️ Nnụnụ dị ka Ndị na-ebu Amụma Ihu Igwe",
      "birds_are_exquisitely_sensitive_to_wea": "Nnụnụ nwere mmetụta dị ukwuu na mgbanwe ihu igwe ma jiri ha mee ihe dị ka “barometer dị ndụ” n'akụkọ ihe mere eme niile:",
      "barometric_pressure": "Nrụgide Barometric: ",
      "birds_can_detect_changes_in_barometric": "Nnụnụ nwere ike ịchọpụta mgbanwe na nrụgide barometric n'ihi ndị nnata pụrụ iche na ntị etiti (akụkụ paratympanic). Mgbe nrụgide dara tupu oké mmiri, nnụnụ na-efekarị ala ma na-eri nri nke ọma karịa. Nnụnụ swallow na-efe ala bụ ihe ngosi oké mmiri ọdịnala.",
      "some_birds_can_hear_infrasound_below_2": "Ụfọdụ nnụnụ nwere ike ịnụ infrasound (n'okpuru 20 Hz) nke a na-emepụta ọbụna site na oké mmiri dị anya, ebili mmiri oke osimiri na ala ọma jijiji. Dị ka ndị mbufe GPS chọpụtara, Golden-winged Warblers hapụrụ Tennessee awa 24 tupu usoro oké ifufe rute na 2014. Ha fere karịa maịl 900 iji zere oké mmiri.",
      "cold_fronts": "Ihu Oyi: ",
      "autumn_migration_is_strongly_correlate": "Mbugharị mgbụsị akwụkwọ nwere njikọ siri ike na ngafe nke ihu oyi. Nnụnụ na-efe n'elu ikuku ugwu-ọdịda anyanwụ n'azụ ihu oyi, nke na-enye ma ikuku azụ ma mbara igwe dị ọcha. Ndị na-ekiri nnụnụ nwere ahụmịhe na-enyocha maapụ ihu igwe iji buo amụma abalị kachasị elu nke mbugharị.",
      "fog_is_dangerous_for_migrating_birds_b": "Alụlụ dị ize ndụ maka nnụnụ na-akwaga n'ihi na ọ na-ezochi akara ala na akara nchọgharị mbara igwe. Abalị alụlụ nwere ntọala igwe ojii dị ala na-eweta “ọdịda”, ebe nnụnụ na-akwaga ike gwụrụ na-arịda n'ìgwè na ebe obibi mbụ dị. Ihe omume ndị a, ọ bụ ezie na ọ na-enye nnụnụ nchekasị, na-emepụta ohere nkiri nnụnụ mara mma.",
      "when_the_swallows_fly_high_the_weather": "“Ọ bụrụ na nnụnụ swallow efee elu, ihu igwe ga-akọ. Ọ bụrụ na nnụnụ swallow efee ala, mmiri ozuzo dị n'ụzọ.” — Ilu ọdịnala a bụ n'ezie ziri ezi na sayensị: ụmụ ahụhụ (nri nnụnụ swallow) na-efe elu na usoro nrụgide dị elu na ala tupu oké mmiri.",
      "particle_color_guide": "🎨 Ntụziaka Agba Irighiri ihe",
