      "red_zone_downwash_sinking_air": " Mpaghara Uhie = ikuku-ala (ikuku na-emikpu)",
      "delaware_bay": "Delaware Bay",
      "over_1_million_shorebirds_stop_here_to": "Ihe karịrị nde nnụnụ mmiri 1 na-akwụsị ebe a iji rie akwa nshịkọ ịnyịnya",
      "gulf_coast": "Ụsọ Oké Osimiri Gulf",
