      "fun_fact": "Eziokwu Na-atọ Ụtọ: ",
      "the_four_north_american_flyways": "🗺️ Ụzọ Ọfụfe Anọ nke North America",
      "atlantic_2": "Atlantic",
      "mississippi_2": "Mississippi",
      "central_2": "Etiti",
      "pacific_2": "Pacific",
      "when_do_birds_migrate": "📅 Kedu Mgbe Nnụnụ na-akwaga?",
      "migration_timing_varies_dramatically_b": "Oge mbugharị na-adịgasị iche nke ukwuu dabere na ụdị:",
      "early_spring_waterfowl_ducks_geese_hea": "Mmalite opupu ihe ubi: Nnụnụ mmiri (ọbọgwụ, ọgazị) na-aga ugwu na-eso mgbaze ice. Red-winged Blackbirds na-alaghachi n'ala mmiri.",
      "peak_spring_warblers_vireos_tanagers_f": "Elu opupu ihe ubi: Warblers, vireos na tanagers na-ejupụta ugwu. Ọtụtụ nnụnụ na-abụ abụ na-akwaga n'abalị. N'abalị kachasị elu enwere ihe karịrị nde nnụnụ 500 na mbara igwe.",
      "shorebirds_start_south_some_species_fa": "Nnụnụ mmiri na-amalite ndịda — ụfọdụ ụdị “dara” n'ebe amụ ma malite ịlaghachi n'oge mbụ Julaị. Ndị okenye na-apụkarị tupu ụmụ nnụnụ.",
      "peak_fall_raptors_ride_thermals_along_": "Elu mgbụsị akwụkwọ: Nnụnụ na-achụ nta na-anọkwasị usoro okpomọkụ n'akụkụ usoro ugwu. Nnụnụ na-abụ abụ na-aga ndịda na-eso ihu oyi. Ọgazị na-efe na nhazi V n'abalị.",
      "photoperiod_day_length_is_the_primary_": "Ogologo ehihie bụ ihe kpatara mbugharị bụ isi. Ka ụbọchị na-adị mkpụmkpụ n'oge mgbụsị akwụkwọ, homonụ na-akpali “Zugunruhe” — enweghị izu ike nke mbugharị — nnụnụ na-amalite ịchịkọta abụba (oke oriri), mgbe ụfọdụ na-eme ka ịdị arọ ahụ mụbaa okpukpu abụọ.",
      "stopover_ecology": "⛺ Gburugburu Ebe Nkwụsị",
      "stopovers_are_not_just_rest_stops_they": "Ebe nkwụsị abụghị naanị ebe izu ike, ha bụ ",
      "refueling_stations": "ebe mgbaju mmanụ",
      "critical_to_survival_a_migrating_warbl": " dị mkpa maka nlanarị. Warbler na-akwaga nwere ike iji 75% nke oge mbugharị n'ebe nkwụsị, na-eri nri dị ka onye ara iji wughachi abụba. Ezigbo ebe obibi nkwụsị nwere ike ịbụ ọdịiche n'etiti ndụ na ọnwụ.",
      "at_delaware_bay_over_1_million_shorebi": "Na Delaware Bay, ihe karịrị nde nnụnụ mmiri 1 (Red Knots, Ruddy Turnstones, Sanderlings) na-adabere na akwa nshịkọ ịnyịnya nke ha yiri na Mee. Oge ga-adịrịrị zuru oke: nnụnụ na-abịa kpọmkwem n'oge nshịkọ ịnyịnya na-eyi akwa. Ọ bụrụ na ọnụ ọgụgụ nshịkọ ịnyịnya adaa (n'ihi ịkụ azụ oke maka mbọ), agbụ mbugharị dum na-adaru.",
      "conservation_success_story_after_horse": "Akụkọ ihe ịga nke ọma nchekwa: Mgbe e webatara oke owuwe ihe ubi nshịkọ ịnyịnya na 2012, ọnụ ọgụgụ Red Knot malitere ịgbake nwayọọ nwayọọ site na obere nsogbu nke 15,000 ruo karịa 50,000 ka ọ na-erule 2025.",
      "migration_physiology": "🦴 Physiology Mbugharị",
      "migration_is_one_of_the_most_physicall": "Mbugharị bụ otu n'ime ọrụ kachasị chọọ ike n'ahụ n'alaeze anụmanụ. Nnụnụ na-agafe mgbanwe ahụ dị ịtụnanya tupu ha apụọ:",
      "hyperphagia": "Oke Oriri",
      "before_migration_birds_enter_a_feeding": "Tupu mbugharị, nnụnụ na-abanye n'ọgụ nri a na-akpọ oke oriri, na-eri nri n'ọnụego okpukpu 2-3 karịa nke nkịtị. Blackpoll Warbler (gram 12) na-atụkwasị abụba nke gram 8-12, na-eme ka ịdị arọ ahụ mụbaa ihe fọrọ nke nta okpukpu abụọ. Abụba a bụ mmanụ maka ọfụfe na-akwụsịghị karịa maịl 2,000.",
      "organ_shrinkage": "Mbelata Akụkụ Ahụ",
      "to_reduce_weight_migrating_birds_actua": "Iji belata ịdị arọ, nnụnụ na-akwaga na-ebelata akụkụ mgbari nri (afọ, imeju, akpa nri) ruo 40% tupu ọpụpụ. Mgbe ha rutere n'ebe nkwụsị, ha na-ewughachi akụkụ ndị a ngwa ngwa iji gbaju mmanụ. “Mgbanwe phenotype” a pụrụ iche n'etiti anụmanụ nwere ọkpụkpụ azụ.",
      "hemoglobin": "Hemoglobin",
      "high_altitude_migrants_like_bar_headed": "Ndị na-akwaga ịdị elu dị elu dị ka Bar-headed Geese (na-efe ụkwụ 29,000 n'elu Himalaya) nwere hemoglobin pụrụ iche nwere mmasị karịa maka oxygen. Akwara ha nwere myoglobin ọzọ, na njupụta capillary ha okpukpu abụọ nke ụdị ala dị ala.",
      "sleep_in_flight": "Ụra n'Ọfụfe",
      "some_birds_can_sleep_while_flying_usin": "Ụfọdụ nnụnụ nwere ike ịrahụ ụra ka ha na-efe, na-eji “ụra ọkara isi” — na-emechi otu ọkara isi n'otu oge. E dekọrọ Frigatebirds ka ha na-arahụ ụra nkeji 42 kwa ụbọchị n'oge ọfụfe ụbọchị 10 nke ịgafe oke osimiri, na-ewere obere ụra nke sekọnd 12 nke ọ bụla.",
      "navigation_clock": "Elekere Nchọgharị",
      "birds_maintain_an_internal_circadian_c": "Nnụnụ na-edobe elekere circadian dị n'ime nke nwere izi ezi dị ịtụnanya. Elekere a na-akwụ ụgwọ mmegharị anyanwụ na mbara igwe (kompas anyanwụ e mezigharịrị oge) ma na-eso mgbanwe oge nke ogologo ehihie nke na-akpali homonụ mbugharị.",
      "zugunruhe": "Zugunruhe",
      "zugunruhe_migration_restlessness_is_a_": "Zugunruhe (“enweghị izu ike nke mbugharị”) bụ ọnọdụ omume ebe nnụnụ na-akwaga a kpọchiri n'ọnyà na-akụ nku n'ntụzịaka nke ha ga-akwaga n'ụzọ okike, n'oge ha ga-akwaga. Ọ bụ nke homonụ na-akpali ma e depụta ya na mkpụrụ ndụ ihe nketa. Ọbụna nnụnụ e ji aka zụlite nke na-enweghị ahụmịhe mbugharị na-egosi Zugunruhe.",
      "species_comparison": "📊 Ntụnyere Ụdị",
