      "6_000_ft_2": "ụkwụ 6,000",
      "distances_are_approximate_annual_migra": "Anya bụ ihe dị ka anya mbugharị kwa afọ. Ọsọ bụ ọsọ njem nkịtị. Ịdị elu bụ ịdị elu mbugharị nkịtị.",
      "how_scientists_track_migration": "📡 Otú Ndị Sayensị si Eso Mbugharị",
      "our_understanding_of_migration_has_bee": "Nghọta anyị nke mbugharị agbanweela site na teknụzụ:",
      "bird_banding": "Ịkpụ Nnụnụ Ihe: ",
      "since_1920_over_80_million_birds_have_": "Kemgbe 1920, e kpụla ihe karịrị nde nnụnụ 80 ihe na North America. Ihe ọ bụla nwere nọmba pụrụ iche. Mgbe ejidere nnụnụ e kpụrụ ihe ọzọ, ndị sayensị na-amụta banyere nlanarị, ụzọ na oge. Ọnụego mgbake dị ala (1-5%), mana data buru ibu nke ukwuu.",
      "gps_trackers": "Ndị na-eso GPS: ",
      "solar_powered_gps_tags_now_as_small_as": "Akara GPS nke anyanwụ na-enye ike (ugbu a dị obere dị ka gram 1) na-eziga data ọnọdụ site na satịlaịtị. Ha na-ekpughe ụzọ ziri ezi, oge nkwụsị na ịdị elu ọfụfe. E ji GPS soro ọfụfe Godwit nke maịl 7,145 na-akwụsịghị.",
      "light_level_geolocators_0_5g_record_su": "Ndị na-achọpụta ọnọdụ ọkwa ìhè (gram 0.5) na-edekọ oge ọwụwa anyanwụ na ọdịda anyanwụ. Mgbe ejidere nnụnụ ọzọ, ndị sayensị na-ewepụta data ma gbakọọ latitude (site na ogologo ehihie) na longitude (site na oge etiti ehihie anyanwụ). Izi ezi: ~200 km.",
      "weather_radar": "Radar Ihu Igwe: ",
      "nexrad_weather_radar_stations_across_t": "Ebe radar ihu igwe NEXRAD gafee US na-achọpụta ìgwè nnụnụ na-akwaga buru ibu. BirdCast (Cornell Lab) na-eji mmụta igwe iji buo amụma ma gosi mbugharị n'oge dị adị site na data radar. N'abalị kachasị elu, radar na-egosi ntụpọ akwụkwọ ndụ buru ibu nke mbugharị nnụnụ.",
      "citizen_scientists_submit_100_million_": "Ndị sayensị obodo na-enyefe ihe karịrị nde nleba anya nnụnụ 100 kwa afọ site na eBird, na-emepụta nchekwa data ọdịdị iche iche kachasị ukwuu n'ụwa. Data a na-ekpughe usoro oge na nkesa mbugharị nke ọkwa kọntinent nke ọ nweghị otu ndị nnyocha nwere ike ịnakọta naanị ha.",
      "motus_wildlife_tracking": "Nsochi Anụ Ọhịa Motus: ",
      "a_network_of_1_500_automated_radio_tel": "Netwọk nke ihe karịrị ebe 1,500 nke telemetry redio akpaghị aka gafee kọntinent America na-achọpụta nnụnụ e kpụrụ akara ka ha na-efe. Ebe ọ bụla na-ege ntị na ụda redio pụrụ iche, na-emepụta netwọk nchọpụta nke ọkwa kọntinent. A na-achọpụta nnụnụ e kpụrụ akara nke na-efe site na Canada ruo Brazil site na ọtụtụ ebe n'ụzọ.",
      "angle_of_attack": "Akụkụ Mbuso Agha:",
      "stall": "⚠ Ịkwụsị",
      "lift_coeff_c": "Coefficient Mbuli (Cₗ)",
      "drag_coeff_c": "Coefficient Ịdọkpụ (Cₑ)",
      "l_d_ratio": "Nha L/D",
      "wing_type_comparison": "Ntụnyere Ụdị Nku",
      "flight_physics_explained": "📚 Akọwara Physics Ọfụfe",
      "bernoulli_s_principle": "Ụkpụrụ Bernoulli",
      "as_air_speeds_up_its_pressure_drops_a_": "Ka ikuku na-agba ọsọ, nrụgide ya na-adaba. Elu nku dị elu gbagọrọ agbagọ na-amanye ikuku ka ọ na-asọ ọsọ n'elu karịa n'okpuru. Nke a na-emepụta ",
      "lower_pressure_above": "nrụgide dị ala n'elu",
      "higher_pressure_below": "nrụgide dị elu n'okpuru",
      "the_wing_generating_lift": " nke nku, na-emepụta mbuli.",
      "p_pv_pgh_constant": "P + ½pv² + pgh = mgbe niile",
      "angle_of_attack_stall": "Akụkụ Mbuso Agha na Ịkwụsị",
      "as_the_angle_of_attack_increases_lift_": "Ka akụkụ mbuso agha na-abawanye, mbuli na-abawanye — ruo otu ebe. ",
      "critical_angle": "Akụkụ dị egwu",
      "stall_angle_airflow_separates_from_the": " (akụkụ ịkwụsị) gafere, mmegharị ikuku na-ekewa site n'elu dị elu. Nku na-atụfu mmegharị ikuku dị nro, mbuli na-adaba nke ukwuu, ịdọkpụ na-awụlikwa. Nke a bụ “ịkwụsị”.",
