      "reynolds_number": "Nọmba Reynolds",
      "bird_flight_operates_at_reynolds_numbe": "Ọfụfe nnụnụ na-arụ ọrụ na nọmba Reynolds n'etiti 10,000 na 500,000 — usoro aerodynamic siri ike. N'ọ̀tụ̀tụ̀ ndị a oyi nsọtụ (ntakịrị ikuku rapaara n'elu nku) bụ akụkụ laminar, akụkụ na-akpali. Abụba nnụnụ na-emepụta obere mkpọtụ nke n'ezie ",
      "maintain_airflow_attachment_especially": " na-edobe njikọ mmegharị ikuku, karịsịa n'akụkụ mbuso agha buru ibu. Nke a bụ ihe ndị injinia ka na-agbalị imepụtaghachi na nhazi drone.",
      "bio_inspired_engineering": "⚙️ Injinịa Ndụ Kpaliri",
      "bird_flight_has_inspired_countless_eng": "Ọfụfe nnụnụ akpaliela ọtụtụ ihe ọhụrụ injinịa a na-apụghị ịgụta ọnụ:",
      "winglets": "Winglets",
      "the_upturned_wingtips_on_modern_airlin": "Nsọtụ nku e tụgharịrị n'elu na ụgbọ elu njem nke oge a (Boeing 737 MAX, Airbus A350) ka abụba nsọtụ e kewara nke egbe kpaliri kpọmkwem. “Winglets” ndị a na-ebelata ịdọkpụ e mepụtara na 5-7%, na-echekwara ụlọ ọrụ ụgbọ elu ọtụtụ ijeri mmefu mmanụ kwa afọ. Ha na-arụ ọrụ site n'ịgbaji ikuku nsọtụ nku.",
      "owl_quiet_fans": "Fan Ndị Dị Jụụ dị ka nke Ikwiikwii",
      "owl_feathers_have_a_serrated_leading_e": "Abụba ikwiikwii nwere nsọtụ ihu nwere ezé, nhazi elu dị ka velvet, na nsọtụ azụ nwere ihe ncha, nke ọnụ na-ebelata mkpọtụ aerodynamic ihe fọrọ nke nta ka ọ bụrụ jụụ. Ndị injinia na GE na Dyson ṅomiri njiri ndị a na blades turbine na nhazi fan, na-ebelata mkpọtụ karịa decibels 10.",
      "kingfisher_bullet_trains": "Ụgbọ Oloko Mgbọ nke Kingfisher Kpaliri",
      "the_shinkansen_bullet_train_s_nose_was": "E mezigharịrị imi ụgbọ oloko mgbọ Shinkansen mgbe injinia na-ekiri nnụnụ Eiji Nakatsu hụrụ ka kingfisher na-amiba site n'ikuku ruo na mmiri na-enweghị ịgba mmiri. Imi nwere ọdịdị ọnụ kingfisher belatara mgbawa ụda na 30% na iji ọkụ eletriki na 15% ka ụgbọ oloko na-apụ site n'ọwara.",
      "morphing_wings": "Nku Na-agbanwe Ọdịdị",
      "birds_continuously_adjust_wing_shape_a": "Nnụnụ na-agbanwe ọdịdị nku, akụkụ na ọnọdụ abụba mgbe niile ka ha na-efe — nke ọma karịa ụgbọ elu ọ bụla. NASA na MIT na-emepụta teknụzụ “nku na-agbanwe ọdịdị” nke na-eji ihe ndị dị mfe na actuators iji ṅomie nhazigharị nku nnụnụ, ikekwe na-eme ka arụmọrụ dịkwuo mma na 8-12%.",
      "feather_engineering": "🪶 Injinịa Abụba",
      "a_bird_feather_is_one_of_the_most_comp": "Abụba nnụnụ bụ otu n'ime ihe owuwu kachasị mgbagwoju anya n'okike. Abụba ọfụfe nwere:",
      "the_central_shaft_a_hollow_tube_strong": "Osisi etiti — tube tọgbọ chakoo, siri ike karịa nchara na nha ịdị arọ, e ji beta-keratin mee.",
      "hundreds_of_branches_growing_from_the_": "Ọtụtụ narị alaka na-eto site n'osisi, na-emepụta akwụkwọ abụba.",
      "tiny_hook_like_structures_connecting_b": "Obere ihe owuwu dị ka nko na-ejikọ alaka dị ka velcro. Otu abụba nduru nwere ihe dị ka nde obere nko 1.",
      "microscopic_hooks_on_barbules_that_zip": "Obere nko microscopic na barbules nke na-ejikọ alaka dị ka zip, na-emepụta elu na-adịghị ekwe ikuku. Mgbe abụba fesara, nnụnụ nwere ike iji ọnụ ya bọọ ya ma “zip” ya ọzọ.",
      "flight_feathers_are_asymmetric_the_lea": "Abụba ọfụfe adịghị nhata — akwụkwọ nsọtụ ihu dị warịị karịa nsọtụ azụ. Enweghị nhata a na-emepụta ọdịdị airfoil gbagọrọ agbagọ nke na-emepụta mbuli, dị ka nku ụgbọ elu. Abụba bụ isi na nsọtụ nku na-atụgharị n'oge ọkụ-ala, na-arụ ọrụ dị ka blades propeller n'otu n'otu.",
      "birds_have_1_000_25_000_feathers_a_swa": "Nnụnụ nwere abụba 1,000 ruo 25,000 (swan nwere nke kachasị). Ha na-agbanwe abụba ọfụfe ha niile kwa afọ n'oge ",
      "typically_after_breeding_season_and_be": ", na-abụkarị mgbe oge amụmụ gasịrị na tupu mbugharị. Ịtụfu ọtụtụ abụba n'otu oge nwere ike ime ka nnụnụ ghara ife, ya mere ntụpọ abụba na-eso nhata akụkụ abụọ ziri ezi: a na-agbanwe abụba dabara na nku ọ bụla n'otu oge.",
