      "metacarpals_phalanges_hand": "Metacarpals & Phalanges (Aka)",
      "scaphoid_bone": "Ọkpụkpụ Scaphoid",
      "600_muscles_movement_posture_heat_prod": "Akwara 600+ — mmegharị, ọnọdụ ahụ, mmepụta okpomọkụ, nkwụsi ike nkwonkwo.",
      "rotator_cuff_sits": "Rotator Cuff (SITS)",
      "iliopsoas": "Iliopsoas",
      "intercostal_muscles": "Akwara Etiti Ọgịrịga",
      "pelvic_floor_levator_ani": "Ala Pelvic (Levator Ani)",
      "diaphragm_muscle": "Diaphragm (Akwara)",
      "heart_60_000_miles_of_vessels_5l_of_bl": "Obi, kilomita 60,000 nke akwara ọbara, lita 5 nke ọbara — na-ebuga O₂, nri, homonu; na-ewepụ mkpofu.",
      "circle_of_willis": "Circle of Willis",
      "great_saphenous_vein": "Akwara Ọbara Saphenous Ukwu",
      "lymphatic_vessels": "Akwara Lymph",
      "cns_brain_spinal_cord_and_pns_31_spina": "CNS (ụbụrụ + eriri azụ) na PNS (ụzọ abụọ 31 nke akwara ozi azụ, ụzọ abụọ 12 nke akwara ozi isi, usoro akwara na-achị onwe ya).",
      "lightest_sleep_transition_from_wakeful": "Ụra kacha dị mfe — mgbanwe site na ịmụ anya. Mmegharị anya nwayọọ nwayọọ, ike akwara na-agbada. Ịma jijiji hypnic (mmegharị myoclonic) bụ ihe nkịtị. A na-akpọte ngwa ngwa. Ebili mmiri vertex dị nkọ na-apụta na EEG.",
      "true_sleep_begins_core_body_temperatur": "Ezigbo ụra na-amalite. Okpomọkụ ime ahụ na-agbada, ọkụkọ obi na-ejie. Sleep spindles (mgbawa thalamocortical) na-echebe ụra ma na-eme ka ncheta mmegharị sie ike. K-complexes bụ ebili mmiri buru ibu na-aza ihe kpalie site na-mpụga.",
      "deep_slow_wave_sleep_sws_most_restorat": "Ụra miri emi/nke ebili mmiri nwayọ (SWS). Ọkwa kacha eweghachi ike. Mmepụta homonu uto na-eru elu. Usoro glymphatic na-ehichapụ mkpofu ụbụrụ (amyloid-β). Nkwado ncheta nkọwa na-eme. Ọ kacha sie ike ịkpọte; ịda mba ụra ma a kpọtee.",
      "dreaming_stage_brain_is_highly_active_": "Ọkwa nrọ. Ụbụrụ na-arụsi ọrụ ike (dị ka ịmụ anya) mana ahụ kwụsịrị (atonia site na mgbochi akwara ozi mmegharị nke azụ ụbụrụ). Mmegharị anya ngwa ngwa nke jikọtara ọnụ. Nhazi ncheta mmetụta uche na idozi nsogbu site na okike. Okirikiri na-atọ ogologo ka abalị na-aga.",
      "cerebral_cortex_4_lobes": "Cortex Ụbụrụ (Lobe 4)",
      "brodmann_areas_map_52_cytoarchitectura": "Mpaghara Brodmann na-ese mpaghara 52 nke nhazi mkpụrụ ndụ. Isi cortex mmegharị (mpaghara 4), isi cortex mmetụta ahụ (mpaghara 3,1,2), isi cortex ọhụụ (mpaghara 17), isi cortex nụ (mpaghara 41,42). Cortex prefrontal bụ nke ikpeazụ na-enweta myelin (~afọ 25).",
      "purkinje_cells_are_among_the_largest_n": "Mkpụrụ ndụ Purkinje so na akwara ozi kacha buru ibu, nke ọ bụla na-enweta ihe dị ka 200,000 nke ntinye synaptic. Cortex cerebellar nwere akwa 3: molecular, Purkinje, granular. Nyocha ọhụrụ na-egosi ọrụ ha na nghọta, mmetụta uche, na asụsụ.",
      "brainstem_midbrain_pons_medulla": "Azụ Ụbụrụ (Etiti Ụbụrụ, Pons, Medulla)",
      "contains_nuclei_for_cranial_nerves_iii": "Ọ nwere nuclei maka akwara ozi isi III–XII. Usoro reticular activating (RAS) bụ \"mgbanye\" nke ụbụrụ — mmebi na-akpata koma. Nkewa piramid na medulla: mgbafe mmegharị na-akọwa njikwa mmegharị nke akụkụ dị iche.",
      "memory_replay_during_sleep_hippocampal": "Nkwughachi ncheta n'oge ụra: akwara ozi hippocampal na-\"akwụghachi\" ahụmịhe ehihie n'oge ụra N3, na-ebufe ncheta na neocortex. Mkpụrụ ndụ grid na cortex entorhinal na-enye mkpụrụ ndụ ebe hippocampal ntụaka mbara.",
      "fear_conditioning_pathway_auditory_cor": "Ụzọ nkuzi egwu: cortex nụ → amygdala akụkụ → amygdala etiti → hypothalamus (nzaghachi nchekasị) + PAG (ịkwụsị). Mmekọrịta amygdala-prefrontal na-enye ohere njikwa mmetụta uche — ntọala ọgwụgwọ CBT.",
      "key_nuclei_vpl_vpm_somatosensory_relay": "Nuclei dị mkpa: VPL/VPM (mbufe mmetụta ahụ), LGN (mbufe ọhụụ na V1), MGN (mbufe nụ na A1), pulvinar (nlebara anya), otu nuclei ihu (ncheta, okirikiri Papez).",
      "thermostat_analogy_anterior_hypothalam": "Ihe atụ thermostat: hypothalamus ihu na-akpali njụ oyi (mgbasa akwara ọbara, ọsụsọ); hypothalamus azụ na-akpali ọkụ (ịma jijiji, mkpọ akwara ọbara). Ahụ ọkụ = ọkwa e welitere site na prostaglandin site na ọrịa.",
      "split_brain_experiments_revealed_hemis": "Nnwale nkewa ụbụrụ kpughere ọpụrụiche akụkụ: akụkụ aka ekpe = asụsụ, mgbagha; akụkụ aka nri = nhazi mbara, nke zuru oke. A na-ahazi ozi e gosiri otu mpaghara ọhụụ site na akụkụ dị iche.",
      "dopamine_from_substantia_nigra_modulat": "Dopamine site na substantia nigra na-achịkwa ụzọ kpọmkwem (D1, na-akpali) na nke na-adịghị kpọmkwem (D2, na-egbochi). Ịtụfu njikwa a na Parkinson na-akpata nsogbu pụrụ iche nke ịmalite mmegharị.",
      "cranial_nerves_i_xii": "Akwara Ozi Isi (I-XII)",
      "returns_interstitial_fluid_absorbs_die": "Na-eweghachi mmiri dị n'etiti mkpụrụ ndụ, na-emikpu abụba nri, nleba anya nchebe — akpụ lymph 600–700, thymus, spleen.",
      "major_visceral_organs_respiration_dige": "Akụkụ ahụ ime dị mkpa — iku ume, mgbari nri, ịzacha, njikwa endocrine.",
      "integumentary": "Akpụkpọ ahụ",
      "skin_largest_organ_2m_hair_nails_gland": "Akpụkpọ ahụ (akụkụ ahụ kachasị ukwuu, ~2m²), ntutu, mbọ, akpụ — mgbochi, njikwa okpomọkụ, mmetụta, mmepụta vitamin D.",
