      "gas_exchange": "Mgbanwe Gas",
      "the_circulatory_system_delivers_deoxyg": "Usoro mgbasa ọbara na-ebuga ọbara na-enweghị oxygen na ngụgụ, ebe usoro iku ume na-ejupụta ya oxygen ma wepụ carbon dioxide site na akpụkpọ alveoli-capillary dị mpempe.",
      "neuromuscular_junction": "Njikọ Akwara-Akwara Ahụ",
      "motor_neurons_from_the_nervous_system_": "Akwara ozi mmegharị site na usoro akwara na-ahapụ acetylcholine na njikọ akwara-akwara ahụ, na-akpali mkpọ eriri akwara. Na-enweghị akara akwara, akwara ahụ enweghị ike ịmegharị.",
      "lever_system_for_movement": "Usoro Lever maka Mmegharị",
      "muscles_attach_to_bones_via_tendons_an": "Akwara na-arapara na ọkpụkpụ site na tendon ma na-adọkpụ gafee nkwonkwo, na-emepụta usoro lever. Ọkpụkpụ ahụ na-enye lever siri ike; akwara na-enye ike ịdọkpụ.",
      "hormonal_regulation_of_reproduction": "Njikwa Homonu nke Ọmụmụ",
      "the_hypothalamus_pituitary_axis_releas": "Axis hypothalamus-pituitary na-ahapụ FSH na LH nke na-achịkwa akụkụ ọmụmụ. Estrogen, progesterone, na testosterone site na akụkụ ọmụmụ na-enyeghachi nzaghachi na usoro endocrine.",
      "immune_defense_and_fluid_balance": "Nchekwa Ọgụ na Nguzozi Mmiri",
      "the_lymphatic_system_returns_interstit": "Usoro lymph na-eweghachi mmiri dị n'etiti mkpụrụ ndụ na mgbasa ọbara ma na-ezipụ mkpụrụ ndụ nchebe emere na akụkụ lymph. Usoro abụọ na-echekwa homeostasis mmiri ma na-alụso ọrịa ọgụ.",
      "hypothalamic_pituitary_axis_2": "Axis Hypothalamic-Pituitary",
      "the_hypothalamus_bridges_the_nervous_a": "Hypothalamus na-ejikọ usoro akwara na endocrine — ọ na-ejikọ akara akwara ma na-atụgharị ha ka ọ bụrụ iwu homonu na-achịkwa akpụ pituitary na usoro homonu niile dị n'okpuru ya.",
      "breathing_mechanics": "Usoro Iku Ume",
      "the_diaphragm_and_intercostal_muscles_": "Diaphragm na akwara etiti ọgịrịga na-agbasa ma na-akpakọ oghere obi n'ụzọ anụ ahụ iji megharịa ikuku. Ngụgụ enweghị akwara nke ha ma na-adabere kpamkpam na akwara gbara ya gburugburu.",
