      "u_s_ccss_m_adopted_in_most_states_expl": "A nabatara CCSS-M nke US n'ọtụtụ steeti. Ọ na-akpọ n'ụzọ doro anya \"concrete models\" na \"manipulatives\" maka K-5 — na-adọta usoro Montessori, Cuisenaire, na Singapore n'ime standards mba.",
      "virtual_manipulatives": "Virtual Manipulatives",
      "web_based_tools_like_this_one_let_stud": "Ngwaọrụ weebụ dị ka nke a na-enye ụmụ akwụkwọ ohere iji manipulatives ọdịnala mee ihe ebe ọ bụla. Nkuzi ahụ bụ otu; naanị ụzọ agbanweela.",
      "sumerian_sexagesimal": "Sexagesimal Ndị Sumer",
      "the_sumerians_use_a_base_60_system_sex": "Ndị Sumer jiri usoro base-60 (sexagesimal) — a ka na-ahụ ya na nkeji sekọnd 60 anyị na okirikiri digrii 360. Base-60 nwere ọtụtụ divisors, nke mara mma na mgbakọ.",
      "archimedes": "Archimedes",
      "approximates_by_inscribing_polygons_in": "Ọ na-eme atụmatụ π site n'idenye polygons n'ime okirikiri na iji polygons gbaa ya gburugburu. Ọ na-akpachi π n'etiti 3 10/71 na 3 1/7.",
      "algebra": "Algebra",
      "al_khw_rizm_s_algebra_is_geometric_he_": "Algebra nke Al-Khwārizmī bụ nke geometry — ọ na-emecha squares N'EZIE site n'ise rectangles. Algebra nke manipulative dị ochie karịa algebra nke symbols.",
      "liber_abaci_in_detail": "Liber Abaci (n'ụzọ zuru ezu)",
      "fibonacci_s_book_includes_a_problem_ab": "Akwụkwọ Fibonacci gụnyere nsogbu gbasara ọmụmụ oke bekee nke na-emepụta Fibonacci sequence: 1, 1, 2, 3, 5, 8, 13... Otu ọnụọgụgụ ndị a na-apụta n'okike na na tilings pattern-block.",
      "oughtred_publishes_clavis_mathematicae": "Oughtred bipụtara Clavis Mathematicae",
      "in_addition_to_inventing_the_slide_rul": "Na mgbakwunye na ịchepụta slide rule, Oughtred wetara symbol × maka ịba ụba. (Leibniz kpọrọ ya asị: o chere na × yiri variable x nke ukwuu.)",
      "euler_is_born": "A mụrụ Euler",
      "leonhard_euler_will_give_us_e_i_for_1_": "Leonhard Euler ga-enye anyị e, i maka √(−1), function-notation f(x), na Euler formula. Geoboards na-egosi formula ya nke \"V − E + F = 2\" maka polyhedra.",
      "friedrich_fr_bel_s_gifts": "Onyinye Friedrich Fröbel",
      "building_on_fr_bel_s_19th_century_kind": "Na-ewuli n'elu \"onyinye\" kindergarten Fröbel nke narị afọ nke 19 (manipulatives osisi), Edith Somervell bipụtara A Rhythmic Approach to Mathematics — curriculum mbụ jupụtara na manipulative.",
      "cuisenaire_s_rods_discovered": "A chọpụtara rods Cuisenaire",
      "georges_cuisenaire_a_belgian_school_pr": "Georges Cuisenaire, onyeisi ụlọ akwụkwọ Belgium, ejirila rods nwere agba mee ihe n'ọtụtụ afọ 4 na nzuzo. Nleta nke onye nyocha butere mbipụta; nnabata na-aga nwayọ ruo 1950s.",
      "caleb_gattegno_s_tour": "Njem Caleb Gattegno",
      "gattegno_tours_uk_schools_demonstratin": "Gattegno gara njem n'ụlọ akwụkwọ UK na-egosi Cuisenaire rods. Nnabata gbawara. Ka ọ na-erule 1960s rods ndị ahụ dị na klas n'ofe Europe na Commonwealth.",
      "nctm_standards": "Standards NCTM",
      "the_national_council_of_teachers_of_ma": "National Council of Teachers of Mathematics wepụtara ntuziaka na-akwado manipulatives na grades niile. Mgbanwe site na mmesi ike procedure ruo nke concept malitere n'ezie na klas US.",
      "nctm_curriculum_evaluation_standards": "NCTM Curriculum & Evaluation Standards",
      "the_seminal_nctm_document_that_anchore": "Akwụkwọ NCTM dị mkpa nke kwadoro \"reform math.\" Ọ na-akpọ idozi nsogbu, ntụle, nkwurịta okwu, na njikọ dị ka isi. Manipulatives ghọrọ ngwaọrụ nkịtị.",
      "nctm_principles_and_standards": "NCTM Principles and Standards",
      "updated_standards_add_a_representation": "Standards e melitere tinyere Representation strand: ụmụ akwụkwọ kwesịrị inwe ike ịtụgharị n'etiti representations anụ ahụ, foto, symbol, na ọnọdụ — ya bụ, CRA loop.",
      "common_core_in_detail": "Common Core n'ụzọ zuru ezu",
      "ccss_m_explicitly_names_number_lines_t": "CCSS-M na-akpọ n'ụzọ doro anya number lines, ten frames, base-10 blocks, na area models. Mathematical practices (MP1-MP8) na-ehazi OTÚ ụmụ akwụkwọ kwesịrị isi jikọọ na manipulatives.",
      "mathematics_is_older_than_writing_ever": "💡 Mgbakọ dị ochie karịa ederede. Manipulative ọ bụla na ngwaọrụ a bụ nwa nke ihe ochie. ",
      "showing_students_the_lineage_this_is_t": "Igosi ụmụ akwụkwọ agbụrụ ahụ — \"nke a bụ otu echiche ahụ nna nna nna nna unu jiri mee ihe\" — na-eme ka mgbakọ bụrụ ihe mmadụ mepụtara, ọ bụghị ihe omimi a ga-eburu n'isi.",
