      "an_arpeggiator_plays_the_notes_of_a_ch": "🔬 Arpeggiator na-akpọ notes nke chord otu n'otu n'usoro. \"Elu\" na-esite n'ala gaa n'elu, na-emepụta ike na-arịgo. \"Ala\" na-agbada maka mmetụta mmiri ọdịda. Ọsọ na-achịkwa ọsọ (ntakịrị = ngwa ngwa). Gate na-achịkwa ogologo oge note ọ bụla na-ada (100% = legato, 10% = staccato). Nwaa ọsọ=100ms + octaves 4 + up pattern maka classic trance arp!",
      "live_mic_effects_lab": "🎤 Live Mic Effects Lab",
      "sing_speak_or_play_an_instrument_hear_": "Bụọ abụ, kwuo okwu, ma ọ bụ kpọọ ngwá egwu — nụ effects na oge ozugbo!",
      "monitor_hear_yourself_use_headphones": "🔊 Monitor (nụ onwe gị — jiri headphones!)",
      "microphone_monitor_volume": "Volume monitor microphone",
      "how_effects_change_sound_waves": "🔬 Ka Effects Si Agbanwe Sound Waves",
      "filter_cutoff": "Filter (Cutoff)",
      "removes_frequencies_above_lowpass_or_b": "Na-ewepụ frequencies dị n'elu (lowpass) ma ọ bụ n'okpuru (highpass) threshold. Dịka iji aka kpuchie ọnụ — frequencies dị elu na-apụ, ụda na-aghọ \"gbara ọchịchịrị\" karịa.",
      "delay": "Delay",
      "creates_echoes_by_copying_the_signal_a": "Na-emepụta echoes site n'idetu signal na ịkpọ ya ọzọ mgbe obere oge gasịrị. Feedback na-achịkwa ọnụ ọgụgụ echoes na-emegharị.",
      "reverb_2": "Reverb",
      "simulates_room_acoustics_by_creating_t": "Na-eṣepụ acoustics ọnụ ụlọ site n'imepụta ọtụtụ puku obere echoes na-agwakọta ọnụ. Obere ọnụ ụlọ = reverb dị mkpụmkpụ, katidral = reverb ogologo.",
      "distortion": "Distortion",
      "clips_the_waveform_peaks_turning_smoot": "Na-ebipụ peaks nke waveform, na-atụgharị sine waves dị nro ka ọ bụrụ ụdị siri ike, nwere nkuku. Nke a na-agbakwụnye harmonics ọhụrụ nke na-adịghị na ụda mbụ.",
      "chorus": "Chorus",
      "duplicates_the_signal_with_a_slight_co": "Na-edetu signal na obere delay na-agbanwe mgbe niile. Nke a na-eṣepụ ọtụtụ voices/ngwá egwu na-akpọ ọnụ na-enweghị nhata ntakịrị.",
      "tremolo": "Tremolo",
      "rapidly_varies_the_volume_up_and_down_": "Na-agbanwe volume elu na ala ngwa ngwa, na-emepụta mmetụta na-akụ. Nke a na-ahụkarị na surf guitar na egwu organ.",
      "use_headphones_when_monitoring_to_avoi": "Jiri headphones mgbe ị na-elele iji zere feedback loops! Mic na-agafe effects niile dị n'elu (filter, delay, reverb, wdg.) — dozie ha ka ị nụ ka nke ọ bụla si agbanwe olu gị ma ọ bụ ngwá egwu gị.",
      "connect_your_microphone_to_run_your_vo": "Jikọọ microphone gị iji gbaa olu gị ma ọ bụ ngwá egwu gị site na effects chain na oge ozugbo.",
      "see_your_voice_as_a_waveform_frequency": "Lee olu gị dịka waveform + frequency spectrum. Nụ ka filter, delay, reverb, distortion, na chorus si agbanwe sound waves n'anụ ahụ.",
      "xy_performance_pad": "🎯 XY Performance Pad",
      "touch_drag_x_pitch_y_filter_effect": "Metụ & dọkpụrụ — X = pitch, Y = filter/effect",
      "xy_pad_performance": "XY Pad Performance",
      "the_xy_pad_maps_your_finger_mouse_posi": "XY pad na-eserịta ọnọdụ mkpịsị aka/mouse gị na musical parameters na oge ozugbo. X axis na-achịkwa pitch (aka ekpe = ala, aka nri = elu). Y axis na-achịkwa filter cutoff frequency (elu = ìhè, ala = ọchịchịrị). Nke a yiri ngwá egwu dịka Korg Kaoss Pad, nke gbanwere live electronic music performance site n'ịtụgharị 2D gestures ka ọ bụrụ ụda.",
      "xy_performance_pad_left_right_is_pitch": "XY performance pad. Aka ekpe–aka nri bụ pitch, elu–ala bụ filter brightness. Jiri arrow keys ịkwaga ma kpọọ note; pịa Escape ma ọ bụ Space ịkwụsị.",
