      "earth_s_magnetic_field_deflects_charge": "Ubi magnet Ụwa na-achụpụ mkpụrụ anyanwụ nwere ọkụ eletrik. Ozone na-enyere aka na UV, mana ubi magnet bụ ọta izizi!",
      "the_iau_s_2006_definition_requires_pla": "Nkọwa IAU nke 2006 chọrọ ka mbaraụwa kpochapụ agbata obi okirikiri ha site na mkpọfu ndị ọzọ.",
      "also_called_the_goldilocks_zone_not_to": "A na-akpọkwa ya 'ebe Goldilocks' — ọ dịghị ọkụ nke ukwuu, ọ dịghị oyi nke ukwuu maka mmiri mmiri n'elu.",
      "the_moon_rotates_exactly_once_per_orbi": "Ọnwa na-agba gburugburu naanị otu ugboro kwa okirikiri — ike mmiri mmiri kpatara nhazi a n'ime ijeri afọ.",
      "opportunity_rover_found_hematite_blueb": "Rover Opportunity chọtara 'blueberries' hematite — mineral ndị na-eme naanị na mmiri. Foto okirikiri na-egosi delta osimiri ochie!",
      "venus_is_hotter_462_c_vs_430_c_mercury": "Venus dị ọkụ karịa (462°C na 430°C)! Mercury enweghị ikuku ga-ejide okpomọkụ. Mmetụta ụlọ enyo dị mkpa karịa anya.",
      "gas_giants_have_no_solid_surface_they_": "Nnukwu mbaraụwa gas enweghị elu siri ike! Ha bụ gas haịdrojen na hịlium nke na-abawanye ịdị arọ nwayọọ nwayọọ ruo n'etiti. Ngwá nyocha ga-anọgide na-emikpu ebighị ebi.",
      "earth_s_distance_from_the_sun_doesn_t_": "Anya dị n'etiti Ụwa na Anyanwụ adịghị agbanwe n'ime otu ụbọchị. Ehihie pụtara naanị na Anyanwụ kacha elu n'eluigwe gị. Ụwa kacha nso na Jenụwarị (perihelion)!",
      "jupiter_is_11x_wider_than_earth_and_1_": "Jupiter sara mbara ugboro 11 karịa Ụwa, Ụwa 1,300 nwekwara ike ịba n'ime ya! Usoro anyanwụ nwere nnukwu ọdịiche n'ịdị ukwuu.",
      "pluto_is_still_in_the_solar_system_it_": "Pluto ka dị na usoro anyanwụ! A gbanwere ya site na 'mbaraụwa' gaa 'obere mbaraụwa' na 2006, mana ọ ka na-agba Anyanwụ gburugburu.",
      "the_asteroid_belt_is_mostly_empty_spac": "Belt asteroid bụ ebe efu n'ihe ka ọtụtụ! Anya dị n'etiti asteroid bụ nde kilomita. Ụgbọ elu mbara igwe na-agafe n'enweghị ihe ize ndụ.",
      "not_always_saturn_is_95x_earth_s_mass_": "Ọ bụghị mgbe niile! Ibu Saturn bụ ugboro 95 nke Ụwa mana ike ndọda n'elu bụ naanị 1.06g n'ihi na ọ buru ibu ma nwee ntakịrị ịdị arọ. Ibu dabere n'ibu NA obosara.",
      "all_parts_of_the_moon_receive_sunlight": "Akụkụ Ọnwa niile na-enweta ìhè anyanwụ! 'Akụkụ dị anya' bụ naanị ọkara anyị na-apụghị ịhụ site na Ụwa n'ihi njikọ mmiri mmiri. Ọ na-enweta anyanwụ otu aka ahụ.",
      "the_habitable_zone": "Ebe A Ga-ebi",
      "the_habitable_zone_or_goldilocks_zone_": "Ebe a ga-ebi (ma ọ bụ 'ebe Goldilocks') bụ ogo anya site na kpakpando ebe mmiri mmiri nwere ike ịdị n'elu mbaraụwa. Na usoro anyanwụ anyị, Venus dị n'ọnụ ime, Ụwa dị n'etiti, Mars dịkwa n'ọnụ èzí. Mana mmiri mmiri chọkwara ikuku na ubi magnet ziri ezi!",
      "the_greenhouse_effect": "Mmetụta Ụlọ Enyo",
      "when_sunlight_heats_a_planet_s_surface": "Mgbe ìhè anyanwụ na-ekpo elu mbaraụwa ọkụ, elu na-ezipụ okpomọkụ (infrared). Gas ụlọ enyo (CO₂, CH₄, H₂O) na-amịkọrọ okpomọkụ a ma zipụ ya ọzọ, na-ekpo mbaraụwa ọkụ. Ụlọ enyo Ụwa bụ +33°C (na-echekwa ndụ). Nke Venus bụ +510°C (adịghị achịkwa). Mars enweghị ọbụna (nkezi -60°C). Ọnụọgụ gas ụlọ enyo na-ekpebi ihe ga-eme!",
      "magnetic_shields": "Ọta Magnet",
      "a_planet_s_magnetic_field_creates_a_ma": "Ubi magnet mbaraụwa na-emepụta 'magnetosphere' — ọta a na-adịghị ahụ anya nke na-achụpụ ifufe anyanwụ (mkpụrụ nwere ọkụ eletrik si n'Anyanwụ). Magnetosphere Ụwa na-echebe ikuku anyị ma mee ka ndụ kwe omume. Mars tụfuru ubi magnet ya ijeri afọ 4 gara aga, e wepụkwara ikuku ya nwayọọ nwayọọ. Magnetosphere Jupiter siri ike ugboro 20,000 karịa nke Ụwa!",
      "why_isn_t_pluto_a_planet": "Gịnị Mere Pluto Ejighị Bụrụ Mbaraụwa?",
      "in_2006_the_international_astronomical": "Na 2006, Òtù Ndị Ọkà Mmụta Kpakpando Ụwa Niile (IAU) kọwara ihe atọ maka mbaraụwa: (1) Na-agba Anyanwụ gburugburu ✓, (2) Nwere ibu zuru ezu maka ụdị gburugburu ✓, (3) 'Ekpochapụla okirikiri ya' nke mkpọfu ndị ọzọ ✗. Pluto na-ekekọrịta ebe okirikiri ya na puku ihe Belt Kuiper, ya mere e kewara ya 'obere mbaraụwa.' Nke a emeghị ka ọ ghara ịdị mkpa — New Horizons gosipụtara na ọ na-arụ ọrụ n'ụdị ala!",
      "tidal_locking": "Njikọ Mmiri Mmiri",
      "over_billions_of_years_gravitational_t": "N'ime ijeri afọ, ike mmiri mmiri nwere ike ibelata ntụgharị ọnwa ruo mgbe ọ dabara na ogologo okirikiri ya. Nsonaazụ: otu ihu na-eche mbaraụwa mgbe niile. Ọnwa anyị jikọtara na Ụwa. Mercury jikọtara akụkụ na Anyanwụ (oke 3:2). Pluto na Charon jikọtara onwe ha — ha na-egosi ibe ha otu ihu mgbe niile!",
      "searching_for_life": "Na-achọ ndụ",
      "a_biosignature_is_any_evidence_of_past": "Akara ndụ (biosignature) bụ ihe ọ bụla na-egosi ndụ gara aga ma ọ bụ nke ugbu a. Ndị ọkà mmụta sayensị na-achọ: (1) mmiri mmiri, (2) mkpụrụ organic, (3) gas ikuku dị ka ọksijen ma ọ bụ metan nke na-agaghị adị ma ọ bụrụ na ndụ emepụtaghị ha, (4) isi iyi ike. Ebe kacha mma na usoro anyanwụ anyị: Mars (mmiri ochie), Europa (oke osimiri n'okpuru elu), Enceladus (isi iyi mmiri), na Titan (ọdọ mmiri metan).",
