      "connect_every_n_th_nail_an_envelope_cu": "Jikọọ ntu n ọ bụla; akụkụ envelop ga-apụta. Mary Everest Boole webatara nke a dịka mgbakọ na mwepụ ụlọ akwụkwọ n'ihe dị ka afọ 1900. Cardioid nke ahịrị kwụ ọtọ ka na-atọ ụtọ.",
      "op_art_fooling_the_visual_system": "Op Art — ịghọgbu usoro ọhụụ",
      "bridget_riley_s_moir_fields_vasarely_s": "Ubi moiré nke Bridget Riley, grid nke Vasarely. Sel ọnụ nke ụbụrụ na-achọpụta mmegharị na-agba ọkụ karịa akarị na ndịiche na-agbanwe ngwa ngwa — peeji ahụ na-adị ka ọ na-*ama jijiji*.",
      "tessellation_the_17_wallpaper_groups": "Nkedo Taịlị — otu 17 nke ụkpụrụ mgbidi",
      "every_periodic_2d_tiling_fits_one_of_1": "Nkedo taịlị 2D ọ bụla na-emegharị na-adaba n'otu n'ime otu nhata 17 ahụ. Escher chọpụtara nke a mgbe ọ gara Alhambra na 1936; o wee were afọ 30 na-emecha katalọg ahụ.",
      "fractal_self_similar_at_every_scale": "Fractal — na-eyi onwe ya n'ogo ọ bụla",
      "mandelbrot_1975_cauliflower_coastlines": "Mandelbrot 1975. Kolịflawa, ikpere oke osimiri, akwara ọbara, amụma, obere akpa ngụgụ — ha niile bụ fractal. “Igwe ojii abụghị bọọlụ, ugwu abụghị konu, ogbugbo osisi adịghịkwa nro.”",
      "gradient_smooth_color_transitions": "Gradient — mgbanwe agba dị nro",
      "css_gives_you_linear_radial_and_conic_": "CSS na-enye gị gradient ahịrị, okirikiri, na conic. Egwurugwu nke ezie nwere ìhè na-aga n'ihu (enweghị ọkwa dị iche iche) — “agba 7 nke egwurugwu” bụ nhọrọ Newton nke aka ya maka ihe gbasara egwu.",
      "stereogram_3d_from_a_flat_page": "Stereogram — 3D sitere na peeji dị larịị",
      "90s_magic_eye_craze_each_eye_sees_a_sl": "Mmasị Magic Eye nke afọ 90. Anya ọ bụla na-ahụ ụdị gbanwere ntakịrị; ọ bụrụ na ị gafere ma ọ bụ kewaa anya gị nke ọma, ụbụrụ gị ga-ejikọta ha ka ha bụrụ omimi. Ihe dị ka 5% ndị mmadụ enweghị ike n'ezie — ọ bụghị mmejọ ha.",
      "contrast_wcag_4_5_1_3_1_apca": "Ndịiche — WCAG 4.5:1 / 3:1 / APCA",
      "wcag_2_1_normal_text_4_5_1_large_3_1_w": "WCAG 2.1: ederede nkịtị 4.5:1, nke buru ibu 3:1. Ihe kpatara ndịiche dị ala ji emerụ ndị na-ahụ ụzọ nke ọma ahụ, ọbụlagodi na ị nwere ike ịgụ ya. APCA (onye nọchiri WCAG 3.0) na-eji ìhè nghọta, ọ bụghị ọnụọgụgụ ìhè nkịtị.",
